def is_private_ip(ip_str):
    """Check if an IP address is private or reserved"""
    try:
        ip = ipaddress.ip_address(ip_str)
        
        # Check if it's a loopback, private, link-local, or reserved address
        if ip.is_loopback or ip.is_private or ip.is_link_local or ip.is_reserved:
            return True
        
        # Additional check against our defined ranges
        for network in PRIVATE_IP_RANGES:
            if ip in network:
                return True
        
        # Block multicast and other special ranges
        if ip.is_multicast:
            return True
            
        return False
    except ValueError:
        return True  # If we can't parse it, block it


def validate_hostname(hostname):
    """Validate that hostname doesn't resolve to private IPs"""
    if not hostname:
        return False
    
    # Block localhost variations
    localhost_patterns = [
        r'^localhost$',
        r'^127\.',
        r'^0\.0\.0\.0$',
        r'^::1$',
        r'^0:0:0:0:0:0:0:1$',
    ]
    
    for pattern in localhost_patterns:
        if re.match(pattern, hostname, re.IGNORECASE):
            return False
    
    # Try to resolve hostname to IP addresses
    try:
        addr_info = socket.getaddrinfo(hostname, None)
        for info in addr_info:
            ip_address = info[4][0]
            if is_private_ip(ip_address):
                return False
    except (socket.gaierror, socket.error):
        return False
    
    return True


def validate_url(url):
    """Comprehensive URL validation with SSRF protection"""
    if not url or not isinstance(url, str):
        return False, "Invalid URL format"
    
    # Basic length check
    if len(url) > 2048:
        return False, "URL too long"
    
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Failed to parse URL"
    
    # Validate scheme
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False, f"Scheme must be one of {ALLOWED_SCHEMES}"
    
    # Validate hostname exists
    if not parsed.hostname:
        return False, "No hostname provided"
    
    # Block IP addresses directly (force domain names)
    try:
        ipaddress.ip_address(parsed.hostname)
        return False, "Direct IP addresses are not allowed"
    except ValueError:
        pass  # Not an IP, which is good
    
    # Validate port if specified
    if parsed.port:
        if parsed.port in BLOCKED_PORTS:
            return False, f"Port {parsed.port} is not allowed"
        if parsed.port < 1 or parsed.port > 65535:
            return False, "Invalid port number"
    
    # Check for credentials in URL
    if parsed.username or parsed.password:
        return False, "URLs with credentials are not allowed"
    
    # Validate hostname doesn't resolve to private IPs
    if not validate_hostname(parsed.hostname):
        return False, "Hostname resolves to private or invalid IP address"
    
    # Block certain TLDs commonly used for internal services
    blocked_tlds = ['.local', '.internal', '.lan', '.corp']
    for tld in blocked_tlds:
        if parsed.hostname.endswith(tld):
            return False, f"TLD {tld} is not allowed"
    
    return True, "Valid"


def setup_chrome_driver():
    """Setup headless Chrome with security options"""
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--window-size=1920,1080')
    chrome_options.add_argument('--disable-web-security')
    chrome_options.add_argument('--disable-features=IsolateOrigins,site-per-process')
    
    # Security: Disable various features that could be exploited
    chrome_options.add_argument('--disable-plugins')
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-popup-blocking')
    
    # Network security
    chrome_options.add_argument('--proxy-server="direct://"')
    chrome_options.add_argument('--proxy-bypass-list=*')
    
    # Set page load timeout
    chrome_options.page_load_strategy = 'normal'
    
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_page_load_timeout(REQUEST_TIMEOUT)
    
    return driver


def take_screenshot(url):
    """Take screenshot with additional runtime validation"""
    driver = None
    try:
        driver = setup_chrome_driver()
        
        # Navigate to URL
        driver.get(url)
        
        # Wait for page to load
        time.sleep(2)
        
        # Verify we didn't get redirected to a private IP
        current_url = driver.current_url
        parsed_current = urlparse(current_url)
        
        if parsed_current.hostname:
            if not validate_hostname(parsed_current.hostname):
                raise Exception("Redirect to private IP detected")
        
        # Take screenshot
        screenshot = driver.get_screenshot_as_png()
        
        return screenshot
    
    finally:
        if driver:
            driver.quit()


def upload_to_s3(screenshot_data, filename):
    """Upload screenshot to S3"""
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=filename,
            Body=screenshot_data,
            ContentType='image/png',
            ACL='public-read'
        )
        
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
        return url
    except Exception as e:
        raise Exception(f"Failed to upload to S3: {str(e)}")


@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    """API endpoint to create screenshot"""
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url'].strip()
        
        # Validate URL with SSRF protection
        is_valid, message = validate_url(url)
        if not is_valid:
            return jsonify({'error': f'Invalid URL: {message}'}), 400
        
        # Generate unique filename
        screenshot_id = str(uuid.uuid4())
        filename = f"screenshots/{screenshot_id}.png"
        
        # Take screenshot
        screenshot_data = take_screenshot(url)
        
        # Upload to S3
        s3_url = upload_to_s3(screenshot_data, filename)
        
        return jsonify({
            'success': True,
            'screenshot_id': screenshot_id,
            'url': s3_url
        }), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500


